#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=1e4+4;

struct Seg{
    ll ux,dx,y;
    int l;
}seg[2*N];

int T,n,w,h,t[8*N],tag[8*N];
map<ll,int> id;
ll tmp[2*N];

bool cmp(Seg u,Seg v){
    return u.y<v.y;
}

void modify(int cur,int l,int r,int x,int y,int k){
    if(x<=l && r<=y){
        t[cur]+=k,tag[cur]+=k;
        return;
    }
    int mid=l+r>>1;
    if(tag[cur]){
        tag[cur*2]+=tag[cur],tag[cur*2+1]+=tag[cur];
        t[cur*2]+=tag[cur],t[cur*2+1]+=tag[cur];
        tag[cur]=0;
    }
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k);
    t[cur]=max(t[cur*2],t[cur*2+1]);
}

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d%d%d",&n,&w,&h);
        for(int i=1;i<=n;i++){
            ll x,y;
            int l;
            scanf("%lld%lld%d",&x,&y,&l);
            seg[2*i-1]={x,x+w,y,l},seg[2*i]={x,x+w,y+h,-l};
            tmp[2*i-1]=x,tmp[2*i]=x+w;
        }
        sort(tmp+1,tmp+2*n+1);
        int len=unique(tmp+1,tmp+2*n+1)-tmp-1;
        for(int i=1;i<=len;i++)
            id[tmp[i]]=i;
        int ans=0;
        memset(t,0,sizeof(t));
        memset(tag,0,sizeof(tag));
        sort(seg+1,seg+2*n+1,cmp);
        for(int i=1;i<=2*n;i++){
            if(seg[i].y>seg[i-1].y)
                ans=max(ans,t[1]);
            modify(1,1,len-1,id[seg[i].ux],id[seg[i].dx]-1,seg[i].l);
        }
        printf("%d\n",ans);
    }
    return 0;
}
